import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

const EditPostPage = () => {
  const { id } = useParams(); // 🔥 get post id from URL

  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [image, setImage] = useState(null);
  const [error, setError] = useState('');

  const [loading, setLoading] = useState(true);
  const [updating, setUpdating] = useState(false);

  const [titleFocus, setTitleFocus] = useState(false);
  const [bodyFocus, setBodyFocus] = useState(false);
  const [btnHover, setBtnHover] = useState(false);
  const [btnActive, setBtnActive] = useState(false);

  const [themeTrigger, setThemeTrigger] = useState(false);

  const { user } = useAuth();
  const navigate = useNavigate();

  // =========================
  // THEME LISTENER
  // =========================
  useEffect(() => {
    const handleThemeChange = () => {
      setThemeTrigger(prev => !prev);
    };
    window.addEventListener("storage", handleThemeChange);
    return () => window.removeEventListener("storage", handleThemeChange);
  }, []);

  const isDark = document.body.classList.contains("dark-mode");

  // =========================
  // FETCH POST DATA
  // =========================
  useEffect(() => {
    const fetchPost = async () => {
      try {
        const res = await API.get(`/posts/${id}`);
        setTitle(res.data.title || '');
        setBody(res.data.body || '');
      } catch (err) {
        setError('Failed to load post');
      } finally {
        setLoading(false);
      }
    };

    fetchPost();
  }, [id]);

  // =========================
  // UPDATE POST
  // =========================
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setUpdating(true);

    const fd = new FormData();
    fd.append('title', title);
    fd.append('body', body);
    if (image) fd.append('image', image);

    try {
      await API.put(`/posts/${id}`, fd);
      navigate(`/posts/${id}`); // 🔥 go back to post page
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to update post');
    } finally {
      setUpdating(false);
    }
  };

  // =========================
  // STYLES (same as create)
  // =========================
  const styles = {
    page: {
      minHeight: '90vh',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      padding: '20px',
      backgroundColor: isDark ? '#560032' : '#FAE8ED',
      fontFamily: 'Georgia, serif',
      color: isDark ? '#f5d6e6' : 'rgb(12, 75, 52)'
    },

    container: {
      width: '100%',
      maxWidth: '700px',
      padding: '30px',
      borderRadius: '20px',
      backgroundColor: isDark ? '#2e091e' : '#f7c6d9',
      boxShadow: isDark
        ? '0 10px 30px rgba(34, 33, 33, 0.6)'
        : '0 10px 30px rgba(0,0,0,0.1)'
    },

    heading: {
      textAlign: 'center',
      marginBottom: '20px'
    },

    form: {
      display: 'flex',
      flexDirection: 'column',
      gap: '18px'
    },

    input: {
      padding: '14px 18px',
      borderRadius: '15px',
      border: '2px solid transparent',
      fontSize: '15px',
      outline: 'none',
      transition: '0.3s',
      backgroundColor: isDark ? '#442c44' : '#FAE8ED',
      color: isDark ? '#fff' : 'rgb(12, 75, 52)'
    },

    inputFocus: {
      backgroundColor: isDark ? '#4a2e4a' : '#ffffff',
      borderColor: isDark ? '#ff7aa2' : 'rgb(12, 75, 52)',
      boxShadow: isDark
        ? '0 5px 15px rgba(255,122,162,0.2)'
        : '0 5px 15px rgba(12,75,52,0.1)'
    },

    textarea: {
      padding: '14px 18px',
      borderRadius: '15px',
      border: '2px solid transparent',
      fontSize: '15px',
      outline: 'none',
      resize: 'none',
      transition: '0.3s',
      backgroundColor: isDark ? '#3a253a' : '#FAE8ED',
      color: isDark ? '#fff' : 'rgb(12, 75, 52)'
    },

    button: {
      padding: '14px',
      borderRadius: '30px',
      border: 'none',
      fontWeight: 'bold',
      cursor: 'pointer',
      backgroundColor: isDark ? '#f8b5cf' : 'rgb(12, 75, 52)',
      color: '#073210',
      transition: '0.3s'
    },

    buttonHover: {
      backgroundColor: '#ff7aa2',
      transform: 'scale(1.05)'
    },

    buttonActive: {
      transform: 'scale(0.97)'
    },

    error: {
      color: '#ff4d4d',
      textAlign: 'center',
      fontSize: '0.9rem'
    }
  };

  const getButtonStyle = () => {
    if (btnActive) return { ...styles.button, ...styles.buttonActive };
    if (btnHover) return { ...styles.button, ...styles.buttonHover };
    return styles.button;
  };

  // =========================
  // LOADING STATE
  // =========================
  if (loading) {
    return <div style={{ textAlign: 'center' }}>Loading post...</div>;
  }

  // =========================
  // UI
  // =========================
  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>Edit Post</h2>

        {error && <p style={styles.error}>{error}</p>}

        <form style={styles.form} onSubmit={handleSubmit}>
          <input
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="Post title"
            required
            style={titleFocus ? { ...styles.input, ...styles.inputFocus } : styles.input}
            onFocus={() => setTitleFocus(true)}
            onBlur={() => setTitleFocus(false)}
          />

          <textarea
            value={body}
            onChange={(e) => setBody(e.target.value)}
            placeholder="Edit your post..."
            rows={12}
            required
            style={bodyFocus ? { ...styles.textarea, ...styles.inputFocus } : styles.textarea}
            onFocus={() => setBodyFocus(true)}
            onBlur={() => setBodyFocus(false)}
          />

          {user?.role === 'admin' && (
            <>
              <input
                type="file"
                onChange={(e) => setImage(e.target.files[0])}
              />
            </>
          )}

          <button
            type="submit"
            disabled={updating}
            style={getButtonStyle()}
            onMouseEnter={() => setBtnHover(true)}
            onMouseLeave={() => setBtnHover(false)}
            onMouseDown={() => setBtnActive(true)}
            onMouseUp={() => setBtnActive(false)}
          >
            {updating ? 'Updating...' : 'Update Post'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default EditPostPage;
